// frontend/src/components/Quiz.js
import React, {useState} from "react";

export default function Quiz({items}) {
  const [answers, setAnswers] = useState({});
  const [showAnswers, setShowAnswers] = useState(false);

  if (!items || items.length===0) return <p>No quiz items generated.</p>;

  const onChange = (i, val) => {
    setAnswers(prev=>({ ...prev, [i]: val }));
  };

  return (
    <div>
      {items.map((it, idx) => (
        <div key={idx} style={{marginBottom:12}}>
          <div><strong>Q{idx+1}:</strong> {it.question}</div>
          <input
            value={answers[idx]||""}
            onChange={(e)=>onChange(idx,e.target.value)}
            placeholder="Type your answer"
            style={{marginTop:6}}
          />
          {showAnswers && (
            <div style={{marginTop:4}}>
              <small>Answer: <em>{it.answer || "(no answer available)"}</em></small>
            </div>
          )}
        </div>
      ))}
      <div style={{marginTop:8}}>
        <button onClick={()=>setShowAnswers(s=>!s)}>{showAnswers?"Hide":"Show"} Answers</button>
      </div>
    </div>
  );
}
